module RefModule(
    input clk,
    input reset,
    input enable,
    input [7:0] d,
    output reg [7:0] q
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset)
            q <= 8'b0;
        else if (enable)
            q <= d;
    end

endmodule
